import{_ as r,C as o,o as n,c as a,a2 as d,E as g}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"AI Agent 工程学 · 技术路线与知识地图","description":"","frontmatter":{},"headers":[],"relativePath":"agent/ai-agent-engineering-roadmap.md","filePath":"agent/ai-agent-engineering-roadmap.md","lastUpdated":1782915681000}'),s={name:"agent/ai-agent-engineering-roadmap.md"};function i(l,t,h,u,A,c){const e=o("Mermaid");return n(),a("div",null,[t[0]||(t[0]=d('<h1 id="ai-agent-工程学-·-技术路线与知识地图" tabindex="-1">AI Agent 工程学 · 技术路线与知识地图 <a class="header-anchor" href="#ai-agent-工程学-·-技术路线与知识地图" aria-label="Permalink to &quot;AI Agent 工程学 · 技术路线与知识地图&quot;">​</a></h1><blockquote><p><strong>一份写给自己的博客写作路线图，覆盖生产级 AI Agent 工程学的完整知识体系。</strong></p><p>未来 18–24 个月，我将在<a href="/agent/">Agent 开发</a>专栏下，按照这条路线逐模块深入学习并输出博客。这篇文章是总目录 —— 每完成一个模块，我会回来把标题改成可点击的链接。</p><p><strong>目标读者画像</strong>：有后端工程经验、已接触 LLM 部署/RAG/MCP/LangGraph/Agent Loop，正在自建 Agent 框架，面向企业/政务客户，目标成长为 AI Agent 基础设施架构师的工程师。</p><p><strong>时效基线</strong>：2026 年年中。所有判断基于一手来源（Anthropic Engineering、各厂商 SDK release、Manus/Sourcegraph 等）。</p></blockquote><hr><h2 id="_0-如何使用这份地图" tabindex="-1">0. 如何使用这份地图 <a class="header-anchor" href="#_0-如何使用这份地图" aria-label="Permalink to &quot;0. 如何使用这份地图&quot;">​</a></h2><p>这份地图有三条正交的轴，任何一个模块都同时挂在这三条轴上：</p><ol><li><strong>工程学纵轴（Stage 0 → 11）</strong>：按操作系统/网络/分布式/LLM/Runtime/Sandbox/Workflow/Multi-Agent/Observability/Platform/Governance 组织，框架只是案例。</li><li><strong>演进史横轴（主线叙事）</strong>：Function Calling → Tool Use → MCP → Context Engineering → Agent Runtime/Harness → Sandbox → Workflow → Agent Platform → Multi-Agent → Cloud Agent → AI-Native Infra。每个技术都放在这条线上讲&quot;为什么出现、上一代为什么不够、未来怎么演进&quot;。</li><li><strong>三套横切体系（贯穿所有阶段）</strong>： <ul><li><strong>A. CS 内核映射</strong>（MIT/CMU/Stanford ↔ Agent 系统）</li><li><strong>B. 源码精读总路线</strong>（精确到入口文件/核心类/关键调用链）</li><li><strong>C. 季度更新机制</strong>（自动纳入新论文/官方博客/Conference）</li></ul></li></ol><p>每个 Stage 的博客都会遵循一个固定结构：<strong>定位 → 为什么（演进史锚点）→ 核心概念 → 关键架构决策（ADR）→ 源码精读 → 横向对比 → 实践 → 持续关注源</strong>。</p><hr><h2 id="_1-全局主线叙事-这套博客要回答的那一个问题" tabindex="-1">1. 全局主线叙事：这套博客要回答的那一个问题 <a class="header-anchor" href="#_1-全局主线叙事-这套博客要回答的那一个问题" aria-label="Permalink to &quot;1. 全局主线叙事：这套博客要回答的那一个问题&quot;">​</a></h2><blockquote><p><strong>&quot;如何把一个无状态的、会幻觉的、按 token 计费的语言模型，变成一个能在生产环境里长时间自主运行、可审计、可治理、可扩展的系统？&quot;</strong></p></blockquote><p>围绕这个问题，整条演进线是这样展开的：</p><table tabindex="0"><thead><tr><th>时代</th><th>核心抽象</th><th>解决了什么</th><th>为什么不够 → 催生下一代</th></tr></thead><tbody><tr><td>2023</td><td><strong>Function Calling</strong></td><td>让模型能触发结构化调用</td><td>每家 schema 不同、工具与 agent 强耦合</td></tr><tr><td>2023–24</td><td><strong>Tool Use / ReAct Loop</strong></td><td>模型在循环里自主用工具</td><td>工具集成 N×M 爆炸、无标准协议</td></tr><tr><td>2024–25</td><td><strong>MCP（Model Context Protocol）</strong></td><td>工具/资源/上下文的标准化接口</td><td>只解决&quot;连接&quot;，不解决&quot;上下文治理&quot;</td></tr><tr><td>2025</td><td><strong>Context Engineering</strong></td><td>把有限的 context 当作稀缺资源来经营</td><td>需要一个能承载它的运行时载体</td></tr><tr><td>2025–26</td><td><strong>Agent Runtime / Harness</strong></td><td>循环、状态、事件流、恢复、compaction</td><td>单机、单租户，无法平台化</td></tr><tr><td>2026</td><td><strong>Agent Platform / Managed Agents</strong></td><td>多租户、托管、meta-harness、会话持久化</td><td>单 agent 能力天花板</td></tr><tr><td>2026+</td><td><strong>Multi-Agent + A2A + Cloud Agent</strong></td><td>agent 之间协作、跨厂商互通</td><td>治理、安全、成本、可靠性成为主战场</td></tr><tr><td>2027?</td><td><strong>AI-Native Infrastructure / OS</strong></td><td>agent 成为一等公民的操作系统级抽象</td><td>—（这是我们要去建设的地方）</td></tr></tbody></table><p><strong>贯穿全程的两个&quot;北极星&quot;判断（2026 已被工业界验证）：</strong></p><ul><li><strong>The Bitter Lesson 适用于 harness 设计</strong>：不要过早训练自己的模型或把假设写死进 harness——模型每次升级都会让一部分 harness 逻辑变成&quot;死重&quot;（Anthropic 在 Sonnet 4.5→Opus 4.5 上亲历：&quot;context anxiety&quot; 的补丁在新模型上变成了 dead weight）。<strong>用 Context Engineering 作为随模型进步而弯曲的柔性接口。</strong></li><li><strong>KV-cache 命中率是生产级 Agent 的头号指标</strong>（Manus 论证：agent 输入输出比约 100:1，缓存 vs 非缓存有约 10x 成本差）。它反过来约束了几乎所有上层设计：稳定前缀、append-only 上下文、&quot;mask 不 remove&quot; 工具。</li></ul><hr><h2 id="_2-阶段依赖关系图" tabindex="-1">2. 阶段依赖关系图 <a class="header-anchor" href="#_2-阶段依赖关系图" aria-label="Permalink to &quot;2. 阶段依赖关系图&quot;">​</a></h2>',16)),g(e,{code:"graph%20TD%0A%20%20%20%20S0%5B%22Stage%200%20%C2%B7%20%E5%B7%A5%E7%A8%8B%E5%93%B2%E5%AD%A6%E4%B8%8E%E5%BF%83%E6%99%BA%E5%9C%B0%E5%9B%BE%20%E2%98%85%E2%98%85%E2%98%85%E2%98%85%E2%98%85%22%5D%0A%20%20%20%20S1%5B%22Stage%201%20%C2%B7%20CS%20%E5%86%85%E6%A0%B8%E9%87%8D%E9%93%B8%20OS%2FNet%2FDistributed%2FPL%20%E2%98%85%E2%98%85%E2%98%85%E2%98%85%22%5D%0A%20%20%20%20S2%5B%22Stage%202%20%C2%B7%20LLM%20%E4%B8%8E%E6%8E%A8%E7%90%86%E5%BC%95%E6%93%8E%E5%BA%95%E5%BA%A7%20%E2%98%85%E2%98%85%E2%98%85%E2%98%85%E2%98%85%22%5D%0A%20%20%20%20S3%5B%22Stage%203%20%C2%B7%20Agent%20%E5%8E%9F%E5%AD%90%E8%83%BD%E5%8A%9B%20FC%2FToolUse%2FMCP%2FContext%2FMemory%20%E2%98%85%E2%98%85%E2%98%85%E2%98%85%E2%98%85%22%5D%0A%20%20%20%20S4%5B%22Stage%204%20%C2%B7%20Agent%20Runtime%20%26%20Harness%EF%BC%88%E6%A0%B8%E5%BF%83%EF%BC%89%E2%98%85%E2%98%85%E2%98%85%E2%98%85%E2%98%85%22%5D%0A%20%20%20%20S5%5B%22Stage%205%20%C2%B7%20%E6%89%A7%E8%A1%8C%E7%8E%AF%E5%A2%83%E4%B8%8E%E6%B2%99%E7%AE%B1%20Sandbox%20%E2%98%85%E2%98%85%E2%98%85%E2%98%85%22%5D%0A%20%20%20%20S6%5B%22Stage%206%20%C2%B7%20Workflow%20%26%20Orchestration%20%E2%98%85%E2%98%85%E2%98%85%E2%98%85%22%5D%0A%20%20%20%20S7%5B%22Stage%207%20%C2%B7%20Multi-Agent%20Systems%20%26%20A2A%20%E2%98%85%E2%98%85%E2%98%85%E2%98%85%22%5D%0A%20%20%20%20S8%5B%22Stage%208%20%C2%B7%20Observability%20%2F%20Eval%20%2F%20Reliability%20%E2%98%85%E2%98%85%E2%98%85%E2%98%85%E2%98%85%22%5D%0A%20%20%20%20S9%5B%22Stage%209%20%C2%B7%20Agent%20Platform%20%26%20Cloud%20Agent%20%E2%98%85%E2%98%85%E2%98%85%E2%98%85%22%5D%0A%20%20%20%20S10%5B%22Stage%2010%20%C2%B7%20Enterprise%20%2F%20Governance%20%2F%20Security%20%2F%20%E6%94%BF%E5%8A%A1%E8%90%BD%E5%9C%B0%20%E2%98%85%E2%98%85%E2%98%85%E2%98%85%E2%98%85%22%5D%0A%20%20%20%20S11%5B%22Stage%2011%20%C2%B7%20Capstone%3A%20Hermes%2FVela%20Platform%20%E2%98%85%E2%98%85%E2%98%85%E2%98%85%E2%98%85%22%5D%0A%0A%20%20%20%20S0%20--%3E%20S1%0A%20%20%20%20S0%20--%3E%20S2%0A%20%20%20%20S1%20--%3E%20S4%0A%20%20%20%20S2%20--%3E%20S3%0A%20%20%20%20S3%20--%3E%20S4%0A%20%20%20%20S4%20--%3E%20S5%0A%20%20%20%20S4%20--%3E%20S6%0A%20%20%20%20S5%20--%3E%20S9%0A%20%20%20%20S6%20--%3E%20S7%0A%20%20%20%20S4%20--%3E%20S8%0A%20%20%20%20S6%20--%3E%20S8%0A%20%20%20%20S7%20--%3E%20S9%0A%20%20%20%20S8%20--%3E%20S9%0A%20%20%20%20S9%20--%3E%20S10%0A%20%20%20%20S10%20--%3E%20S11%0A%20%20%20%20S8%20--%3E%20S11%0A%0A%20%20%20%20subgraph%20%E6%A8%AA%E5%88%87%5B%22%E8%B4%AF%E7%A9%BF%E5%85%A8%E7%A8%8B%E7%9A%84%E6%A8%AA%E5%88%87%E4%BD%93%E7%B3%BB%22%5D%0A%20%20%20%20%20%20%20%20A%5B%22A.%20CS%20%E5%86%85%E6%A0%B8%E6%98%A0%E5%B0%84%22%5D%0A%20%20%20%20%20%20%20%20B%5B%22B.%20%E6%BA%90%E7%A0%81%E7%B2%BE%E8%AF%BB%E6%80%BB%E8%B7%AF%E7%BA%BF%22%5D%0A%20%20%20%20%20%20%20%20C%5B%22C.%20%E5%AD%A3%E5%BA%A6%E6%9B%B4%E6%96%B0%E6%9C%BA%E5%88%B6%22%5D%0A%20%20%20%20end%0A"}),t[1]||(t[1]=d('<p><strong>关键依赖说明：</strong></p><ul><li>Stage 2（LLM 底座）和 Stage 1（CS 内核）可<strong>并行</strong>启动，两者都是 Stage 4 的前置。</li><li>Stage 4（Runtime/Harness）是整张图的重心——它是自建 Agent 框架的直接对照。Stage 5/6/8 都从它分叉。</li><li>Stage 8（Observability/Eval）建议<strong>尽早开始、贯穿始终</strong>（&quot;没有 eval 的 agent 不是工程，是玄学&quot;），图上虽画在中段，但心态上从 Stage 3 就要建立。</li><li>Stage 10（政务/治理）是<strong>差异化护城河</strong>，不是最后才想的事——private deployment / 可审计 / 数据主权的约束会反向影响 Stage 4/5/9 的架构选择。</li></ul><hr><h2 id="_3-阶段总览与博客计划" tabindex="-1">3. 阶段总览与博客计划 <a class="header-anchor" href="#_3-阶段总览与博客计划" aria-label="Permalink to &quot;3. 阶段总览与博客计划&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Stage</th><th>名称</th><th>重要度</th><th>建议周期</th><th>计划博客数</th><th>前置</th><th>状态</th></tr></thead><tbody><tr><td>0</td><td>工程哲学与心智地图</td><td>★★★★★</td><td>2 周</td><td>2–3 篇</td><td>—</td><td>🔜 即将开始</td></tr><tr><td>1</td><td>CS 内核重铸（OS/Net/Distributed/PL/DB）</td><td>★★★★</td><td>8–10 周</td><td>5–6 篇</td><td>S0</td><td>⏳ 计划中</td></tr><tr><td>2</td><td>LLM 与推理引擎底座</td><td>★★★★★</td><td>6–8 周</td><td>4–5 篇</td><td>S0</td><td>⏳ 计划中</td></tr><tr><td>3</td><td>Agent 原子能力</td><td>★★★★★</td><td>8–10 周</td><td>6–8 篇</td><td>S2</td><td>⏳ 计划中</td></tr><tr><td>4</td><td>Agent Runtime &amp; Harness</td><td>★★★★★</td><td>10–12 周</td><td>8–10 篇</td><td>S1,S3</td><td>⏳ 计划中</td></tr><tr><td>5</td><td>执行环境与沙箱</td><td>★★★★</td><td>5–6 周</td><td>3–4 篇</td><td>S4</td><td>⏳ 计划中</td></tr><tr><td>6</td><td>Workflow &amp; Orchestration</td><td>★★★★</td><td>6–8 周</td><td>4–5 篇</td><td>S4</td><td>⏳ 计划中</td></tr><tr><td>7</td><td>Multi-Agent &amp; A2A</td><td>★★★★</td><td>5–6 周</td><td>3–4 篇</td><td>S6</td><td>⏳ 计划中</td></tr><tr><td>8</td><td>Observability / Eval / Reliability</td><td>★★★★★</td><td>6–8 周</td><td>5–6 篇</td><td>S4,S6</td><td>⏳ 计划中</td></tr><tr><td>9</td><td>Agent Platform &amp; Cloud Agent</td><td>★★★★</td><td>8–10 周</td><td>5–6 篇</td><td>S5,S7,S8</td><td>⏳ 计划中</td></tr><tr><td>10</td><td>Enterprise / Governance / Security / 政务</td><td>★★★★★</td><td>6–8 周</td><td>5–6 篇</td><td>S9</td><td>⏳ 计划中</td></tr><tr><td>11</td><td>Capstone: 自建 Agent Platform</td><td>★★★★★</td><td>12–16 周</td><td>4–5 篇</td><td>S10,S8</td><td>⏳ 计划中</td></tr></tbody></table><p><strong>总量估算</strong>：约 55–70 篇博客，覆盖 18–24 个月。按每周 10–12h 学习 + 1–2 篇博客的节奏推进。</p><hr><h2 id="_4-逐阶段博客目录" tabindex="-1">4. 逐阶段博客目录 <a class="header-anchor" href="#_4-逐阶段博客目录" aria-label="Permalink to &quot;4. 逐阶段博客目录&quot;">​</a></h2><h3 id="stage-0-·-工程哲学与心智地图-★★★★★-第-1–2-周" tabindex="-1">Stage 0 · 工程哲学与心智地图 ★★★★★（第 1–2 周） <a class="header-anchor" href="#stage-0-·-工程哲学与心智地图-★★★★★-第-1–2-周" aria-label="Permalink to &quot;Stage 0 · 工程哲学与心智地图 ★★★★★（第 1–2 周）&quot;">​</a></h3><blockquote><p><strong>定位</strong>：在写任何一行代码之前，先建立&quot;为什么&quot;的框架。这是全系列唯一一个&quot;世界观&quot;阶段。</p></blockquote><table tabindex="0"><thead><tr><th>#</th><th>计划文章</th><th>核心内容</th><th>状态</th></tr></thead><tbody><tr><td>0.1</td><td><strong>AI Agent 演进史：从 Function Calling 到 AI-Native Infra</strong></td><td>FC → ToolUse → MCP → ContextEng → Runtime → Platform → MultiAgent → AI-Native 的完整演进叙事</td><td>🔜</td></tr><tr><td>0.2</td><td><strong>The Bitter Lesson 如何影响 Agent 架构设计</strong></td><td>为什么不该过早训模型/写死假设；Context Engineering 作为柔性接口</td><td>🔜</td></tr><tr><td>0.3</td><td><strong>什么是 Agent：定义、边界与争议</strong></td><td>Anthropic 定义 vs 行业分歧；Workflow vs Agent 的决策框架</td><td>🔜</td></tr></tbody></table><p><strong>必读一手资料</strong>：</p><ul><li>Anthropic《Building effective agents》+《Effective context engineering for AI agents》（2025-09）</li><li>Manus《Context Engineering for AI Agents: Lessons from Building Manus》（Part 1 &amp; 2）</li><li>Rich Sutton《The Bitter Lesson》原文</li><li>Anthropic《Scaling Managed Agents: Decoupling the brain from the hands》（2026-04）</li></ul><hr><h3 id="stage-1-·-cs-内核重铸-★★★★-第-3–12-周-⏩-有后端底子-可压缩" tabindex="-1">Stage 1 · CS 内核重铸 ★★★★（第 3–12 周）⏩ 有后端底子，可压缩 <a class="header-anchor" href="#stage-1-·-cs-内核重铸-★★★★-第-3–12-周-⏩-有后端底子-可压缩" aria-label="Permalink to &quot;Stage 1 · CS 内核重铸 ★★★★（第 3–12 周）⏩ 有后端底子，可压缩&quot;">​</a></h3><blockquote><p><strong>定位</strong>：不是从零学 CS，而是<strong>用 Agent 系统的视角重新审视四门核心课</strong>——把 MIT/CMU/Stanford 的经典课程显式映射到 Agent 系统上。</p></blockquote><table tabindex="0"><thead><tr><th>#</th><th>计划文章</th><th>核心内容</th><th>状态</th></tr></thead><tbody><tr><td>1.1</td><td><strong>Agent Runtime 本质是一个操作系统</strong></td><td>进程隔离 ↔ sandbox；调度 ↔ harness；系统调用 ↔ tool；MIT 6.1810 / OSTEP 映射</td><td>⏳</td></tr><tr><td>1.2</td><td><strong>虚拟化与隔离：从 OS 到 Agent Sandbox</strong></td><td>Firecracker microVM ↔ VM；gVisor ↔ 用户态内核；隔离级别选择</td><td>⏳</td></tr><tr><td>1.3</td><td><strong>分布式系统理论如何指导 Agent 状态管理</strong></td><td>状态机复制 ↔ session_events 事实源；事件溯源/CQRS 在 Agent 中的应用；MIT 6.5840 映射</td><td>⏳</td></tr><tr><td>1.4</td><td><strong>RPC、流式协议与幂等：Agent 通信的底层基础</strong></td><td>SSE / streaming / MCP transport / A2A；Stanford CS144 映射</td><td>⏳</td></tr><tr><td>1.5</td><td><strong>编程语言与 Agent：类型系统、AST 与 Code Agent</strong></td><td>tool schema = 类型系统；structured output；Crafting Interpreters</td><td>⏳</td></tr><tr><td>1.6</td><td><strong>数据库理论在 Agent 中的应用</strong></td><td>事务/隔离级别 ↔ 会话持久化；向量库 vs grep 索引的存储引擎取舍；CMU 15-445 映射</td><td>⏳</td></tr></tbody></table><p><strong>核心 ADR</strong>：</p><ul><li>Anthropic 为什么用 <strong>event stream + <code>getEvents()</code> 位置切片</strong> 而不是把 context 存进 sandbox？→ CQRS/事件溯源的直接应用。</li><li>为什么 sandbox 隔离选 <strong>microVM（Firecracker）而不是容器</strong>？→ OS 隔离理论的直接落地。</li></ul><hr><h3 id="stage-2-·-llm-与推理引擎底座-★★★★★-可与-s1-并行-第-3–10-周" tabindex="-1">Stage 2 · LLM 与推理引擎底座 ★★★★★（可与 S1 并行，第 3–10 周） <a class="header-anchor" href="#stage-2-·-llm-与推理引擎底座-★★★★★-可与-s1-并行-第-3–10-周" aria-label="Permalink to &quot;Stage 2 · LLM 与推理引擎底座 ★★★★★（可与 S1 并行，第 3–10 周）&quot;">​</a></h3><blockquote><p><strong>定位</strong>：Agent 工程师必须理解&quot;引擎盖下面&quot;。重点不是训练，而是<strong>推理经济学</strong>。</p></blockquote><table tabindex="0"><thead><tr><th>#</th><th>计划文章</th><th>核心内容</th><th>状态</th></tr></thead><tbody><tr><td>2.1</td><td><strong>KV-cache：Agent 推理经济学的核心</strong></td><td>Attention/KV-cache 原理；为什么前缀稳定 = 缓存命中；100:1 输入输出比的含义</td><td>⏳</td></tr><tr><td>2.2</td><td><strong>vLLM 与 PagedAttention 深入</strong></td><td>连续批处理调度；块表如何让共享前缀零拷贝；prefix caching 与会话路由</td><td>⏳</td></tr><tr><td>2.3</td><td><strong>采样策略与结构化输出：Agent 稳定性的底座</strong></td><td>temperature/top-p；JSON mode / grammar / logit masking；&quot;mask 不 remove&quot;的底层机制</td><td>⏳</td></tr><tr><td>2.4</td><td><strong>Context Rot 与长上下文技术</strong></td><td>context rot / pre-rot threshold（1M 窗口约 256k 就开始退化）；稳定序列化保缓存</td><td>⏳</td></tr><tr><td>2.5</td><td><strong>私有化部署的推理经济学</strong></td><td>昇腾/CUDA/国产化；量化/蒸馏取舍；自托管分布式 KV-cache 的挑战</td><td>⏳</td></tr></tbody></table><p><strong>核心 ADR</strong>：</p><ul><li>为什么 Manus 坚持&quot;<strong>mask token logits 而不是动态增删工具</strong>&quot;？→ 把 Stage 2 的缓存原理直接变成 Stage 3 的工具管理决策。</li><li>为什么 agent 场景比 chatbot 更依赖 prefix caching？→ 100:1 的输入输出比 + 每步 append。</li></ul><hr><h3 id="stage-3-·-agent-原子能力-★★★★★-第-11–20-周" tabindex="-1">Stage 3 · Agent 原子能力 ★★★★★（第 11–20 周） <a class="header-anchor" href="#stage-3-·-agent-原子能力-★★★★★-第-11–20-周" aria-label="Permalink to &quot;Stage 3 · Agent 原子能力 ★★★★★（第 11–20 周）&quot;">​</a></h3><blockquote><p><strong>定位</strong>：构成任何 agent 的最小能力单元。这是主线叙事 FC→ToolUse→MCP→Context→Memory 的落点。</p></blockquote><table tabindex="0"><thead><tr><th>#</th><th>计划文章</th><th>核心内容</th><th>状态</th></tr></thead><tbody><tr><td>3.1</td><td><strong>工具即契约：写给 AI Agent 的工具设计原则</strong></td><td>schema 设计；token 效率；歧义最小化；层级化 action space</td><td>⏳</td></tr><tr><td>3.2</td><td><strong>MCP 协议深入：不止是&quot;工具的 USB-C&quot;</strong></td><td>resources / tools / prompts；transport 层；Linux Foundation 化；治理与命名空间</td><td>⏳</td></tr><tr><td>3.3</td><td><strong>Context Engineering 三原语：Compaction / Clearing / Memory</strong></td><td>三种上下文增长是三个不同问题；compaction 的触发时机与保真度</td><td>⏳</td></tr><tr><td>3.4</td><td><strong>上下文失败模式：Context Rot / Pollution / Confusion</strong></td><td>诊断你的 workload 属于哪一种上下文压力；各自的缓解策略</td><td>⏳</td></tr><tr><td>3.5</td><td><strong>Agentic Search：为什么 grep 正在取代 embedding 预检索</strong></td><td>Anthropic 转向 agentic search 的一手背书；grep/glob 即时检索 vs embedding 预检索；检索质量门</td><td>⏳</td></tr><tr><td>3.6</td><td><strong>Agent Memory：短期/工作记忆与长期记忆的工程实现</strong></td><td>文件系统即上下文（Manus）；/memories 目录；跨会话记忆的写入/召回/淘汰</td><td>⏳</td></tr><tr><td>3.7</td><td><strong>Planning 与 Reasoning：任务分解、Recitation 与自我纠错</strong></td><td>把任务清单反复写回上下文以稳定注意力；保留错误轨迹让模型学习</td><td>⏳</td></tr><tr><td>3.8</td><td><strong>Context Engineering 横向对比：Anthropic vs Manus vs 传统 RAG 派</strong></td><td>检索/工具管理/长任务/北极星四个维度的全面对比</td><td>⏳</td></tr></tbody></table><p><strong>核心 ADR</strong>：</p><ul><li>为什么 Anthropic 从 embedding 预检索转向 <strong>agentic search（grep/glob 即时探索）</strong>？→ 避免陈旧索引、给 agent 按需发现上下文的自主权。chunking 无稳定最优策略，grep 检索绕过了这个不稳定性。</li><li>为什么把 context 管理拆成三个正交原语而不是一个&quot;上下文管理器&quot;？</li></ul><p><strong>横向对比矩阵（Context Engineering）</strong>：</p><table tabindex="0"><thead><tr><th>维度</th><th>Anthropic</th><th>Manus</th><th>传统 RAG 派</th></tr></thead><tbody><tr><td>检索</td><td>agentic search（grep）+ 按需</td><td>文件系统即上下文</td><td>embedding 预检索</td></tr><tr><td>工具管理</td><td>少而精 + 动态发现</td><td>mask 不 remove（logit 掩码）</td><td>全量塞进 prompt</td></tr><tr><td>长任务</td><td>compaction + memory + subagent</td><td>外置文件 + recitation</td><td>塞更大窗口</td></tr><tr><td>北极星</td><td>最小高信号 token 集</td><td>KV-cache 命中率</td><td>召回率</td></tr></tbody></table><hr><h3 id="stage-4-·-agent-runtime-harness-★★★★★-第-21–32-周-·-全系列重心" tabindex="-1">Stage 4 · Agent Runtime &amp; Harness ★★★★★（第 21–32 周）· 全系列重心 <a class="header-anchor" href="#stage-4-·-agent-runtime-harness-★★★★★-第-21–32-周-·-全系列重心" aria-label="Permalink to &quot;Stage 4 · Agent Runtime &amp; Harness ★★★★★（第 21–32 周）· 全系列重心&quot;">​</a></h3><blockquote><p><strong>定位</strong>：把 Stage 1–3 的一切组装成一个能长时间自主运行、可恢复、可观测的<strong>运行时</strong>。这是从&quot;会用 agent&quot;到&quot;能造 agent 平台&quot;的分水岭。</p></blockquote><table tabindex="0"><thead><tr><th>#</th><th>计划文章</th><th>核心内容</th><th>状态</th></tr></thead><tbody><tr><td>4.1</td><td><strong>Agent Loop 解剖：perceive→reason→act→observe</strong></td><td>循环内核；终止条件；预算控制；流式与增量</td><td>⏳</td></tr><tr><td>4.2</td><td><strong>事件流为唯一事实源：Agent 状态管理的正确姿势</strong></td><td>session_events = source of truth；AG-UI = 瞬态投影；CQRS 在 Agent 中的落地</td><td>⏳</td></tr><tr><td>4.3</td><td><strong>RUN_FINISHED.outcome：为什么该用判别联合建模 Agent 终止态</strong></td><td>完成/部分完成/被中断/超预算/被人工接管——联合类型让下游能穷尽处理</td><td>⏳</td></tr><tr><td>4.4</td><td><strong>Meta-Harness 思想：对模型保持&quot;不固执己见&quot;</strong></td><td>借鉴操作系统&quot;为尚未存在的程序设计&quot;的思路；容纳未来 harness 的通用接口</td><td>⏳</td></tr><tr><td>4.5</td><td><strong>崩溃恢复与持久执行：Agent 的&quot;断点续跑&quot;</strong></td><td>从 session 日志重建；session 作为 context window 之外的持久对象</td><td>⏳</td></tr><tr><td>4.6</td><td><strong>Subagents：独立上下文的子 Agent 与隔离模型</strong></td><td>&quot;分享内存靠通信&quot;（Go 并发哲学）；子 agent 的上下文隔离与通信</td><td>⏳</td></tr><tr><td>4.7</td><td><strong>Agent 协议对齐：AG-UI / A2A / MCP 如何在 Runtime 层统一</strong></td><td>三种协议的语义映射；runtime 如何同时对齐</td><td>⏳</td></tr><tr><td>4.8</td><td><strong>Agent Runtime 横向对比：LangGraph vs OpenAI SDK vs Claude Agent SDK vs Manus</strong></td><td>编排范式/状态持久化/独特强项/模型绑定 四维矩阵</td><td>⏳</td></tr><tr><td>4.9</td><td><strong>源码精读：Claude Agent SDK 的 Harness 设计</strong></td><td><code>query()</code> 生成器 → lifecycle hooks → subagents → MCP in-process server</td><td>⏳</td></tr><tr><td>4.10</td><td><strong>源码精读：LangGraph StateGraph / Pregel / Checkpoint</strong></td><td>图执行 + 持久 + 时间旅行调试的完整实现</td><td>⏳</td></tr></tbody></table><p><strong>核心 ADR</strong>：</p><ul><li>为什么把 <strong>session（可恢复存储）与 harness（任意上下文管理）关注点分离</strong>？</li><li>为什么 <code>outcome</code> 该是<strong>判别联合</strong>而不是布尔+错误码？</li><li>STATE_DELTA 为什么要<strong>推迟</strong>到 ownership/持久化边界明确之后？</li></ul><p><strong>横向对比矩阵（Runtime/编排范式，2026 现状）</strong>：</p><table tabindex="0"><thead><tr><th>框架</th><th>编排范式</th><th>状态持久化</th><th>独特强项</th><th>模型绑定</th></tr></thead><tbody><tr><td>LangGraph 1.0</td><td>图（有向图+条件边）</td><td>内置 checkpoint + 时间旅行</td><td>&quot;第 7 步失败怎么办&quot;有一等答案</td><td>无关</td></tr><tr><td>OpenAI Agents SDK</td><td>handoff（显式交接）</td><td>context 变量（默认易失）</td><td>上手最快、guardrails</td><td>OpenAI</td></tr><tr><td>Claude Agent SDK</td><td>tool-use 链 + subagent</td><td>经 MCP</td><td>lifecycle 控制、深 OS 访问</td><td>Claude</td></tr><tr><td>Google ADK 2.0</td><td>图执行</td><td>pluggable session 后端</td><td>多语言、原生 A2A</td><td>偏 Gemini</td></tr><tr><td>MS Agent Framework 1.0</td><td>图 workflow</td><td>—</td><td>合并 AutoGen+SK，.NET</td><td>无关</td></tr><tr><td>Manus</td><td>自研 harness（重写 4 次）</td><td>文件系统 + session</td><td>KV-cache 极致优化</td><td>前沿 API</td></tr></tbody></table><hr><h3 id="stage-5-·-执行环境与沙箱-★★★★-第-33–38-周" tabindex="-1">Stage 5 · 执行环境与沙箱 ★★★★（第 33–38 周） <a class="header-anchor" href="#stage-5-·-执行环境与沙箱-★★★★-第-33–38-周" aria-label="Permalink to &quot;Stage 5 · 执行环境与沙箱 ★★★★（第 33–38 周）&quot;">​</a></h3><blockquote><p><strong>定位</strong>：给 agent 一双&quot;安全的手&quot;。补齐隔离级别理论与 2026 的产品/自托管选型。</p></blockquote><table tabindex="0"><thead><tr><th>#</th><th>计划文章</th><th>核心内容</th><th>状态</th></tr></thead><tbody><tr><td>5.1</td><td><strong>Agent 沙箱的隔离层级：容器 vs microVM vs 用户态内核</strong></td><td>Firecracker / gVisor / 容器 三层隔离-性能-GPU 支持权衡</td><td>⏳</td></tr><tr><td>5.2</td><td><strong>凭证与代理：让 Harness 永不接触密钥</strong></td><td>tool proxy + vault；MCP OAuth token 经 proxy 用 session token 换真实凭证</td><td>⏳</td></tr><tr><td>5.3</td><td><strong>Blast Radius 封顶：Agent 安全边界设计</strong></td><td>权限最小化；能力模型；审计；Anthropic 为 claude.ai/Claude Code/Cowork 建 containment 的经验</td><td>⏳</td></tr><tr><td>5.4</td><td><strong>GPU 沙箱与私有化部署</strong></td><td>VFIO passthrough、MIG 切片给 microVM；A10/910B 场景</td><td>⏳</td></tr></tbody></table><hr><h3 id="stage-6-·-workflow-orchestration-★★★★-第-39–46-周" tabindex="-1">Stage 6 · Workflow &amp; Orchestration ★★★★（第 39–46 周） <a class="header-anchor" href="#stage-6-·-workflow-orchestration-★★★★-第-39–46-周" aria-label="Permalink to &quot;Stage 6 · Workflow &amp; Orchestration ★★★★（第 39–46 周）&quot;">​</a></h3><blockquote><p><strong>定位</strong>：当纯 agent loop 不够可靠时，用确定性编排兜底。</p></blockquote><table tabindex="0"><thead><tr><th>#</th><th>计划文章</th><th>核心内容</th><th>状态</th></tr></thead><tbody><tr><td>6.1</td><td><strong>四种编排范式：Graph / Role / Handoff / Hierarchical</strong></td><td>2026 已定型的四种&quot;真正 ship 的&quot;模式；各自的适配问题形状</td><td>⏳</td></tr><tr><td>6.2</td><td><strong>持久执行：Checkpoint、崩溃恢复与时间旅行调试</strong></td><td>durable workflow；LangGraph Pregel 执行引擎深入</td><td>⏳</td></tr><tr><td>6.3</td><td><strong>Human-in-the-Loop：审批门与人工接管</strong></td><td>中断、人工接管、恢复；监管场景的刚需</td><td>⏳</td></tr><tr><td>6.4</td><td><strong>确定性 vs 自主性：何时该收紧 Agent 的自由度</strong></td><td>&quot;人类工程师都说不清用哪个工具时，agent 更不行&quot;</td><td>⏳</td></tr><tr><td>6.5</td><td><strong>四种编排范式，我该用哪种？决策树</strong></td><td>决策框架 + 实际案例对比</td><td>⏳</td></tr></tbody></table><hr><h3 id="stage-7-·-multi-agent-systems-a2a-★★★★-第-47–52-周" tabindex="-1">Stage 7 · Multi-Agent Systems &amp; A2A ★★★★（第 47–52 周） <a class="header-anchor" href="#stage-7-·-multi-agent-systems-a2a-★★★★-第-47–52-周" aria-label="Permalink to &quot;Stage 7 · Multi-Agent Systems &amp; A2A ★★★★（第 47–52 周）&quot;">​</a></h3><blockquote><p><strong>定位</strong>：从单 agent 到 agent 群落的协作、通信、状态共享。</p></blockquote><table tabindex="0"><thead><tr><th>#</th><th>计划文章</th><th>核心内容</th><th>状态</th></tr></thead><tbody><tr><td>7.1</td><td><strong>多 Agent 协作模式：Supervisor / Swarm / 群聊</strong></td><td>各自的瓶颈（supervisor 是单点）；何时该拆、何时不该拆</td><td>⏳</td></tr><tr><td>7.2</td><td><strong>A2A 协议深入：Agent Card 与跨框架发现</strong></td><td>跨厂商/跨框架的 agent 发现；Linux Foundation 标准化</td><td>⏳</td></tr><tr><td>7.3</td><td><strong>&quot;靠通信共享内存&quot;：多 Agent 的状态隔离哲学</strong></td><td>Manus 引 Go 并发哲学；discrete task 隔离上下文</td><td>⏳</td></tr><tr><td>7.4</td><td><strong>多 Agent 的经济学：15x Token 放大，何时值得？</strong></td><td>成本/收益分析；单 agent+subagent vs 多 agent 实测对比</td><td>⏳</td></tr></tbody></table><hr><h3 id="stage-8-·-observability-eval-reliability-★★★★★-第-53–60-周" tabindex="-1">Stage 8 · Observability / Eval / Reliability ★★★★★（第 53–60 周） <a class="header-anchor" href="#stage-8-·-observability-eval-reliability-★★★★★-第-53–60-周" aria-label="Permalink to &quot;Stage 8 · Observability / Eval / Reliability ★★★★★（第 53–60 周）&quot;">​</a></h3><blockquote><p><strong>定位</strong>：让 agent 从&quot;玄学&quot;变&quot;工程&quot;。这是绝大多数团队的系统性薄弱区，也是建立专业壁垒的地方。</p></blockquote><table tabindex="0"><thead><tr><th>#</th><th>计划文章</th><th>核心内容</th><th>状态</th></tr></thead><tbody><tr><td>8.1</td><td><strong>Agent 可观测性：从零搭建 Tracing 体系</strong></td><td>全链路追踪；每步 cost/latency/质量；LangSmith/Langfuse 数据模型</td><td>⏳</td></tr><tr><td>8.2</td><td><strong>Agent Eval 方法论：为什么 Eval 决定 Agent 能否上生产</strong></td><td>&quot;没有 eval 的 agent 不是工程，是玄学&quot;；LLM-as-judge 的偏差与校准</td><td>⏳</td></tr><tr><td>8.3</td><td><strong>Agent 系统的五维度评估：Cost / Latency / Efficacy / Assurance / Reliability</strong></td><td>五维框架；KV-cache 命中率监控</td><td>⏳</td></tr><tr><td>8.4</td><td><strong>Agent 可靠性工程：失败注入、幂等重试与 SLO</strong></td><td>rerun reliability；agent 系统的 SLO 怎么定</td><td>⏳</td></tr><tr><td>8.5</td><td><strong>构建 Agent 回归测试体系</strong></td><td>eval 集 + 探针问题 + LLM-judge + CI 回归门</td><td>⏳</td></tr><tr><td>8.6</td><td><strong>为什么 &quot;cost per successful task&quot; 比 &quot;GitHub stars&quot; 更该作为选型依据</strong></td><td>生产现实：概率系统，单次成功不代表可复现</td><td>⏳</td></tr></tbody></table><hr><h3 id="stage-9-·-agent-platform-cloud-agent-★★★★-第-61–70-周" tabindex="-1">Stage 9 · Agent Platform &amp; Cloud Agent ★★★★（第 61–70 周） <a class="header-anchor" href="#stage-9-·-agent-platform-cloud-agent-★★★★-第-61–70-周" aria-label="Permalink to &quot;Stage 9 · Agent Platform &amp; Cloud Agent ★★★★（第 61–70 周）&quot;">​</a></h3><blockquote><p><strong>定位</strong>：从&quot;一个 agent&quot;到&quot;一个平台&quot;——多租户、托管、扩缩、控制面。</p></blockquote><table tabindex="0"><thead><tr><th>#</th><th>计划文章</th><th>核心内容</th><th>状态</th></tr></thead><tbody><tr><td>9.1</td><td><strong>Managed Agents 与 Meta-Harness：为尚未存在的 Agent 设计接口</strong></td><td>Anthropic Managed Agents 的接口设计哲学；控制面 vs 数据面</td><td>⏳</td></tr><tr><td>9.2</td><td><strong>AI Gateway：多模型路由、失败转移与成本追踪</strong></td><td>统一网关的分层解耦模式</td><td>⏳</td></tr><tr><td>9.3</td><td><strong>从库到平台：Agent 框架的平台化之路</strong></td><td>多租户 + 配额 + 水平扩展 + warm pool</td><td>⏳</td></tr><tr><td>9.4</td><td><strong>Cloud Agent：长时后台任务、恢复与通知</strong></td><td>远程/后台 agent 的工程挑战</td><td>⏳</td></tr><tr><td>9.5</td><td><strong>Agent 平台横向对比：Managed Agents vs Agent Engine vs Bedrock Agents vs 自建</strong></td><td>托管度/锁定/私有化能力对比</td><td>⏳</td></tr><tr><td>9.6</td><td><strong>2026 生产团队的务实选择：2–3 个 SDK + 一个 Gateway</strong></td><td>为什么不用单一框架；供应商 SDK + 编排框架 + gateway 的分层策略</td><td>⏳</td></tr></tbody></table><hr><h3 id="stage-10-·-enterprise-governance-security-政务落地-★★★★★-第-71–78-周-·-护城河" tabindex="-1">Stage 10 · Enterprise / Governance / Security / 政务落地 ★★★★★（第 71–78 周）· 护城河 <a class="header-anchor" href="#stage-10-·-enterprise-governance-security-政务落地-★★★★★-第-71–78-周-·-护城河" aria-label="Permalink to &quot;Stage 10 · Enterprise / Governance / Security / 政务落地 ★★★★★（第 71–78 周）· 护城河&quot;">​</a></h3><blockquote><p><strong>定位</strong>：把前面所有技术&quot;落到监管环境&quot;。这是相对硅谷工程师的结构性优势：private deployment / 可审计 / 数据主权 / 国产化。</p></blockquote><table tabindex="0"><thead><tr><th>#</th><th>计划文章</th><th>核心内容</th><th>状态</th></tr></thead><tbody><tr><td>10.1</td><td><strong>事件流即审计日志：Agent 系统的可审计性设计</strong></td><td>session_events 天然满足审计；为每个 action 留可追溯轨迹</td><td>⏳</td></tr><tr><td>10.2</td><td><strong>Prompt Injection 攻防：Agent 安全的第一道防线</strong></td><td>间接注入、工具滥用、越权；OWASP LLM/Agent security</td><td>⏳</td></tr><tr><td>10.3</td><td><strong>Agent 供应链安全：MCP Server 与工具的信任边界</strong></td><td>200+ MCP server 生态的治理挑战</td><td>⏳</td></tr><tr><td>10.4</td><td><strong>政务场景的 Agent 私有化部署：离线/国产化/数据不出域</strong></td><td>昇腾 910B4、CANN、离线包、等保、数据分级</td><td>⏳</td></tr><tr><td>10.5</td><td><strong>Agent 治理体系：命名空间、注册表与 CI 强制校验</strong></td><td><code>vela.*</code> CUSTOM 命名空间治理；变更管理与灰度</td><td>⏳</td></tr><tr><td>10.6</td><td><strong>数据主权三角：政务私有化 vs 公有云托管 Agent 的取舍</strong></td><td>数据主权 / 成本 / 能力天花板的平衡</td><td>⏳</td></tr></tbody></table><hr><h3 id="stage-11-·-capstone-自建-agent-platform-★★★★★-第-79–94-周-·-最终整合" tabindex="-1">Stage 11 · Capstone: 自建 Agent Platform ★★★★★（第 79–94 周）· 最终整合 <a class="header-anchor" href="#stage-11-·-capstone-自建-agent-platform-★★★★★-第-79–94-周-·-最终整合" aria-label="Permalink to &quot;Stage 11 · Capstone: 自建 Agent Platform ★★★★★（第 79–94 周）· 最终整合&quot;">​</a></h3><blockquote><p><strong>定位</strong>：把 Stage 0–10 整合成一个自己的、可对外讲、可交付客户的 <strong>Agent Platform</strong>。这个 Capstone 就应该是日常工作本身——学习与工作合一。</p></blockquote><table tabindex="0"><thead><tr><th>#</th><th>计划文章</th><th>核心内容</th><th>状态</th></tr></thead><tbody><tr><td>11.1</td><td><strong>Agent Platform 架构全景：从 Runtime 到 Governance 的七层模型</strong></td><td>完整架构图 + 时序图</td><td>⏳</td></tr><tr><td>11.2</td><td><strong>设计决策记录（ADR）：自建 Agent Platform 的关键取舍</strong></td><td>贯穿全系列的 ADR 汇总与复盘</td><td>⏳</td></tr><tr><td>11.3</td><td><strong>从零到一的 Agent Platform：实现回顾与技术演进</strong></td><td>开发历程、踩坑记录、架构演进</td><td>⏳</td></tr><tr><td>11.4</td><td><strong>评估标准：什么样的 Agent Platform 算&quot;好&quot;？</strong></td><td>能否让一位 Principal Engineer 看完架构文档后说&quot;这个人理解了 harness、context、session 与治理的本质&quot;</td><td>⏳</td></tr><tr><td>11.5</td><td><strong>AI Agent 工程学 2.0：完整的知识体系总结</strong></td><td>系列收官：知识地图全览 + 未来展望</td><td>⏳</td></tr></tbody></table><hr><h2 id="_5-三套横切体系" tabindex="-1">5. 三套横切体系 <a class="header-anchor" href="#_5-三套横切体系" aria-label="Permalink to &quot;5. 三套横切体系&quot;">​</a></h2><h3 id="a-cs-内核映射表-mit-cmu-stanford-↔-agent-系统" tabindex="-1">A. CS 内核映射表（MIT/CMU/Stanford ↔ Agent 系统） <a class="header-anchor" href="#a-cs-内核映射表-mit-cmu-stanford-↔-agent-系统" aria-label="Permalink to &quot;A. CS 内核映射表（MIT/CMU/Stanford ↔ Agent 系统）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>经典课程</th><th>核心概念</th><th>Agent 系统里的化身</th><th>出现在 Stage</th></tr></thead><tbody><tr><td>MIT 6.1810 / OSTEP</td><td>进程隔离、虚拟化、调度</td><td>sandbox、harness 调度、会话进程</td><td>1, 5</td></tr><tr><td>MIT 6.5840 分布式系统</td><td>状态机复制、一致性、容错</td><td>session_events 事实源、恢复</td><td>1, 4</td></tr><tr><td>事件溯源 / CQRS（工程范式）</td><td>日志 + 投影</td><td>session=日志, AG-UI=投影</td><td>4, 10</td></tr><tr><td>Stanford CS144 网络</td><td>RPC、流式、幂等</td><td>streaming、MCP/A2A transport</td><td>1, 7</td></tr><tr><td>Stanford CS143 / Crafting Interpreters</td><td>AST、类型、解释器</td><td>tool schema、code-agent、structured output</td><td>1, 3</td></tr><tr><td>CMU 15-445 数据库</td><td>事务、隔离、存储引擎</td><td>会话持久化、向量库 vs grep</td><td>1, 3</td></tr><tr><td>CMU 15-213（CSAPP）</td><td>系统底层</td><td>推理引擎的内存/缓存直觉</td><td>2</td></tr></tbody></table><blockquote><p><strong>原则</strong>：不为学 CS 而学 CS。每个经典概念都必须指向一个 Agent 系统里的具体决策。</p></blockquote><h3 id="b-源码精读总路线-按依赖排序-精确到入口" tabindex="-1">B. 源码精读总路线（按依赖排序，精确到入口） <a class="header-anchor" href="#b-源码精读总路线-按依赖排序-精确到入口" aria-label="Permalink to &quot;B. 源码精读总路线（按依赖排序，精确到入口）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>顺序</th><th>项目</th><th>入口/核心</th><th>读它学什么</th><th>对应 Stage</th></tr></thead><tbody><tr><td>1</td><td><strong>MCP SDK / FastMCP</strong></td><td>server 注册 + transport</td><td>工具/资源标准化契约</td><td>3</td></tr><tr><td>2</td><td><strong>Anthropic Cookbook</strong> <code>tool_use/context_engineering</code></td><td>compaction/clearing/memory notebook</td><td>context 三原语可运行实现</td><td>3</td></tr><tr><td>3</td><td><strong>Claude Agent SDK</strong></td><td><code>query()</code> 生成器 → hooks → subagents</td><td>最小完整 harness</td><td>4</td></tr><tr><td>4</td><td><strong>Claude Code</strong></td><td>工具/上下文/循环解耦</td><td>unopinionated harness 范例</td><td>4</td></tr><tr><td>5</td><td><strong>LangGraph</strong></td><td><code>StateGraph</code> → <code>Pregel</code> → <code>checkpoint</code></td><td>图执行 + 持久 + 时间旅行</td><td>4, 6</td></tr><tr><td>6</td><td><strong>OpenHands</strong></td><td><code>runtime/base.py</code>(V0) → <code>SandboxService</code>(V1)</td><td>runtime 接口演进</td><td>4, 5</td></tr><tr><td>7</td><td><strong>E2B OSS</strong></td><td>orchestrator + Firecracker host</td><td>microVM 沙箱编排</td><td>5</td></tr><tr><td>8</td><td><strong>vLLM</strong></td><td><code>scheduler.py</code> → <code>attention</code> → prefix cache</td><td>推理经济学底座</td><td>2</td></tr><tr><td>9</td><td><strong>OpenAI Agents SDK</strong></td><td>handoff + sandbox + subagent</td><td>handoff 范式</td><td>4, 7</td></tr><tr><td>10</td><td><strong>Browser Use / OpenManus</strong></td><td>agent + 浏览器/工具编排</td><td>端到端参考实现</td><td>综合</td></tr></tbody></table><blockquote><p><strong>读法</strong>：每个项目先问三件事——<strong>入口在哪？核心抽象是什么？为什么这样设计而不是别的？</strong> 读完写一篇&quot;设计思想复盘 + 我能借鉴什么到自己的框架&quot;。</p></blockquote><h3 id="c-季度更新机制" tabindex="-1">C. 季度更新机制 <a class="header-anchor" href="#c-季度更新机制" aria-label="Permalink to &quot;C. 季度更新机制&quot;">​</a></h3><p><strong>固定订阅（每周扫一遍）</strong>：</p><ul><li>官方 Blog：Anthropic Engineering、OpenAI、Google Research/DeepMind、Microsoft Research</li><li>实践者：Manus Blog、Phil Schmid、Lance Martin、Cognition、Simon Willison</li><li>Release Notes：Claude Agent SDK、LangGraph、Google ADK、MS Agent Framework、vLLM、MCP、A2A、E2B</li></ul><p><strong>每季度一次&quot;课程演进评审&quot;</strong>：</p><ol><li>扫过去 3 个月的顶会（NeurIPS/ICML/ICLR + 系统会 OSDI/SOSP/MLSys）与 arXiv agent/infra 热点。</li><li>检查每个 Stage 的&quot;横向对比矩阵&quot;是否有版本/GA 变动。</li><li>检查协议层（MCP/A2A/AG-UI）有无 RFC/规范更新。</li><li>把新增内容并入对应 Stage，淘汰过时结论。</li><li>产出一篇《本季度 Agent 工程有什么变了》。</li></ol><hr><h2 id="_6-现实排期" tabindex="-1">6. 现实排期 <a class="header-anchor" href="#_6-现实排期" aria-label="Permalink to &quot;6. 现实排期&quot;">​</a></h2><p>考虑到全职工作 + 已有 Agent 项目 + 目标 3–5 年成为架构师：</p><table tabindex="0"><thead><tr><th>时间段</th><th>覆盖 Stage</th><th>关键产出</th><th>博客数</th></tr></thead><tbody><tr><td><strong>第 1–2 月</strong></td><td>S0 全量 + S1/S2 并行快扫</td><td>建立心智框架，补推理经济学</td><td>6–8 篇</td></tr><tr><td><strong>第 3–6 月</strong></td><td>S3 + S4 深耕</td><td><strong>重心阶段</strong>，边学边重构框架</td><td>12–15 篇</td></tr><tr><td><strong>第 7–10 月</strong></td><td>S5/S6/S7 + S8 心态建立</td><td>补齐沙箱/编排/多Agent</td><td>10–12 篇</td></tr><tr><td><strong>第 11–14 月</strong></td><td>S8 深耕 + S9 平台化</td><td>Eval 体系建设 + 框架升级为平台</td><td>10–12 篇</td></tr><tr><td><strong>第 15–18 月</strong></td><td>S10 护城河 + S11 收口</td><td>政务落地模板 + 架构总复盘</td><td>10–13 篇</td></tr><tr><td><strong>全程</strong></td><td>三套横切体系不间断</td><td>每月 ≥1 篇博客；每季度 1 次演进评审</td><td>55–70 篇</td></tr></tbody></table><p><strong>最大化 ROI 的原则</strong>：让 Capstone = 日常工作。凡是能&quot;学一个模块就改进一次自己的框架&quot;的地方，优先做。这不是&quot;额外学习&quot;，而是&quot;把日常工作系统化到架构师的深度&quot;。</p><hr><h2 id="_7-当前进度与已发布文章" tabindex="-1">7. 当前进度与已发布文章 <a class="header-anchor" href="#_7-当前进度与已发布文章" aria-label="Permalink to &quot;7. 当前进度与已发布文章&quot;">​</a></h2><blockquote><p>标注说明：✅ 已发布 | ✍️ 写作中 | 🔜 即将开始 | ⏳ 计划中</p></blockquote><h3 id="已发布的相关文章-agent-开发专栏" tabindex="-1">已发布的相关文章（Agent 开发专栏） <a class="header-anchor" href="#已发布的相关文章-agent-开发专栏" aria-label="Permalink to &quot;已发布的相关文章（Agent 开发专栏）&quot;">​</a></h3><p>以下是 <code>agent/</code> 目录下已发布的文章，它们覆盖了本路线图中的部分内容：</p><table tabindex="0"><thead><tr><th>文章</th><th>对应 Stage/模块</th><th>覆盖情况</th></tr></thead><tbody><tr><td><a href="/agent/ai-agent-engineering">AI Agent 工程化</a></td><td>Stage 0/4</td><td>工程化总览，后续需按本路线深化</td></tr><tr><td><a href="/agent/agent-framework-notes">Agent 框架笔记：先把边界画清楚</a></td><td>Stage 4</td><td>框架设计边界</td></tr><tr><td><a href="/agent/agent-loop-notes">Agent Loop 笔记</a></td><td>Stage 4.1</td><td>Agent 循环内核</td></tr><tr><td><a href="/agent/workflow-notes">Workflow 笔记</a></td><td>Stage 6</td><td>编排初步</td></tr><tr><td><a href="/agent/rag-notes">RAG 笔记</a></td><td>Stage 3.5</td><td>检索增强</td></tr><tr><td><a href="/agent/tool-system-notes">Tool System 笔记</a></td><td>Stage 3.1</td><td>工具系统设计</td></tr><tr><td><a href="/agent/protocol-layer-notes">协议层笔记</a></td><td>Stage 3.2 / 4.7</td><td>MCP 与协议</td></tr><tr><td><a href="/agent/sandbox-notes">Sandbox 笔记</a></td><td>Stage 5</td><td>沙箱初步</td></tr><tr><td><a href="/agent/config-discovery-notes">配置发现笔记</a></td><td>Stage 3</td><td>工具/配置治理</td></tr><tr><td><a href="/agent/architecture-split-notes">架构拆分笔记</a></td><td>Stage 4</td><td>Runtime 架构</td></tr><tr><td><a href="/agent/evolution-notes">演进笔记</a></td><td>Stage 0.1</td><td>演进史初步</td></tr></tbody></table><blockquote><p>已有文章是很好的起点，但按照本路线图的深度标准（ADR + 源码精读 + 横向对比 + CS 内核映射），每个模块都值得重新展开为深度技术文章。</p></blockquote><hr><h2 id="_8-如何使用这份路线图" tabindex="-1">8. 如何使用这份路线图 <a class="header-anchor" href="#_8-如何使用这份路线图" aria-label="Permalink to &quot;8. 如何使用这份路线图&quot;">​</a></h2><p><strong>如果你是读者</strong>：</p><ul><li>这份路线图是一个&quot;知识地图&quot;，不是线性课程。你可以从任何感兴趣的 Stage 开始。</li><li>建议从 <strong>Stage 0</strong>（演进史）开始建立全局视角，然后跳到 <strong>Stage 4</strong>（Runtime/Harness）——它是所有技术的落点。</li><li>每个 Stage 内部按&quot;定位 → 演进史锚点 → 核心概念 → ADR → 源码 → 对比 → 实践&quot;展开。</li></ul><p><strong>如果这是我（作者）</strong>：</p><ul><li>这份路线图既是博客目录，也是学习计划。每完成一个模块，把对应文章的状态从 ⏳ 更新为 ✅，并加上链接。</li><li>优先写那些&quot;学完后能立刻改进自己框架&quot;的模块——学习与工作合一。</li><li>每季度做一次演进评审，更新这份路线图本身（框架版本、协议 RFC、新论文等）。</li></ul><hr><p><em>最后更新：2026-07-01 · 版本 v1.0 · 共 12 个 Stage，计划 55–70 篇文章，预计 18–24 个月完成</em></p>',102))])}const p=r(s,[["render",i]]);export{b as __pageData,p as default};
